def transform(table):
    if not table:
        return []
    header = table[0]
    data = table[1:]
    items = defaultdict(list)
    for row in data:
        item = row[0]
        for col_idx, value in enumerate(row):
            if value:
                date = header[col_idx + 1]
                items[item].append((date, value))
    result = []
    for item, dates_values in items.items():
        dates_values.sort(key=lambda x: x[0])
        for date, value in dates_values:
            result.append([item, date, value])
    return result

