def transform(table):
    if not table:
        return []
    header = table[0]
    data = table[1:]
    if not data:
        return []
    first_row = data[0]
    if len(first_row) != len(header):
        return []
    product_col_idx = header.index("Product")
    price_col_idx = header.index("Price")
    if product_col_idx == -1 or price_col_idx == -1:
        return []
    product_map = {}
    for row in data:
        if len(row) != len(header):
            continue
        product = row[product_col_idx]
        if product not in product_map:
            product_map[product] = []
        product_map[product].append(row)
    result = []
    for product, rows in product_map.items():
        if len(rows) == 1:
            result.append(rows[0])
        else:
            first_row = rows[0]
            for i in range(1, len(rows)):
                new_row = first_row[:]
                new_row.append(rows[i][price_col_idx])
                result.append(new_row)
    return result

