def transform(table):
    if not table:
        return []
    num_cols = len(table[0])
    if num_cols < 2:
        return table

    # Identify column indices for names, subjects, and grades
    name_col = 0
    subject_col = 1
    grade_col = 2

    # Extract unique subjects and grades
    subjects = set()
    grades = set()
    for row in table:
        if len(row) > subject_col:
            subjects.add(row[subject_col])
        if len(row) > grade_col:
            grades.add(row[grade_col])

    # Sort subjects and grades
    sorted_subjects = sorted(subjects)
    sorted_grades = sorted(grades)

    # Initialize result table
    result = [["" for _ in sorted_subjects] + ["" for _ in range(len(sorted_grades))] for _ in range(len(table))]

    # Fill in the data
    for row in table:
        if len(row) > name_col:
            result[0][name_col] = row[name_col]
        for i, subject in enumerate(sorted_subjects):
            if len(row) > subject_col and row[subject_col] == subject:
                result[0][i] = row[subject_col]
        for i, grade in enumerate(sorted_grades):
            if len(row) > grade_col and row[grade_col] == grade:
                result[0][len(sorted_subjects) + i] = row[grade_col]

    # Transpose the result to get the final table
    final_table = []
    for i in range(len(result[0])):
        final_row = []
        for j in range(len(result)):
            final_row.append(result[j][i])
        final_table.append(final_row)

    return final_table

