    if not table or not table[0]:
        return []
    headers = table[0]
    if headers[0] == "":
        headers = headers[1:]
    else:
        headers = headers
    data_rows = table[1:]
    if not data_rows:
        return []
    product_row = data_rows[0]
    if product_row[0] == "":
        product_row = product_row[1:]
    else:
        product_row = product_row
    result = []
    for date in headers:
        for product, values in zip(product_row, data_rows[1:]):
            if product == "":
                continue
            product = product
            for i, value in enumerate(values):
                if i < len(headers):
                    if value == "":
                        continue
                    result.append([date, product, value])
    return result

